class LocationManager(private val context: Context) {

    private val fusedLocationClient =
        LocationServices.getFusedLocationProviderClient(context)

    fun getCurrentDistrict(
        onResult: (String) -> Unit,
        onPermissionDenied: () -> Unit
    ) {
        // Step 1: Check if permission was granted
        val hasPermission = ContextCompat.checkSelfPermission(
            context, Manifest.permission.ACCESS_FINE_LOCATION
        ) == PackageManager.PERMISSION_GRANTED

        if (!hasPermission) {
            onPermissionDenied()  // let caller handle it
            return
        }

        // Step 2: Get location (async — uses callback)
        fusedLocationClient.lastLocation
            .addOnSuccessListener { location ->
                if (location != null) {
                    val district = reverseGeocode(
                        location.latitude,
                        location.longitude
                    )
                    onResult(district ?: "Quận 1")
                } else {
                    onResult("Quận 1")  // default if no cached location
                }
            }
            .addOnFailureListener { onResult("Quận 1") }
    }

    private fun reverseGeocode(lat: Double, lng: Double): String? {
        return try {
            val geocoder = Geocoder(context, Locale("vi", "VN"))
            val addresses = geocoder.getFromLocation(lat, lng, 1)
            addresses?.firstOrNull()?.subAdminArea
        } catch (e: Exception) { null }
    }
}

