// Data model for a single rain report
data class RainReport(
    val id: String = "",
    val district: String = "",
    val timestamp: Long = 0L,
    val intensity: String = "MEDIUM",
    val reporterCount: Int = 1
)

// Enum ensures only valid intensity values are used
enum class RainIntensity {
    LIGHT, MEDIUM, HEAVY;

    fun toVietnamese() = when (this) {
        LIGHT  -> "Mưa nhẹ"
        MEDIUM -> "Mưa vừa"
        HEAVY  -> "Mưa lớn"
    }

    fun markerColor() = when (this) {
        LIGHT  -> 0xFF60A5FA  // blue
        MEDIUM -> 0xFF3B82F6  // darker blue
        HEAVY  -> 0xFFEF4444  // red
    }
}

class ReportManager {
    private val db = Firebase.database.reference

    fun submitReport(report: RainReport, onDone: () -> Unit) {
        val districtKey = report.district
            .lowercase()
            .replace(" ", "-")

        val key = db.child("rain_reports")
            .child(districtKey)
            .push().key ?: return

        val reportWithId = report.copy(id = key)

        db.child("rain_reports")
            .child(districtKey)
            .child(key)
            .setValue(reportWithId)
            .addOnSuccessListener { onDone() }
    }

    fun listenToDistrict(
        district: String,
        onUpdate: (List<RainReport>) -> Unit
    ) {
        val key = district.lowercase().replace(" ", "-")
        db.child("rain_reports").child(key)
            .orderByChild("timestamp")
            .limitToLast(20)
            .addValueEventListener(object : ValueEventListener {
                override fun onDataChange(snapshot: DataSnapshot) {
                    val list = snapshot.children.mapNotNull {
                        it.getValue(RainReport::class.java)
                    }.sortedByDescending { it.timestamp }
                    onUpdate(list)
                }
                override fun onCancelled(error: DatabaseError) {}
            })
    }
}

// Talks to YOUR Firebase database over plain HTTPS — no Firebase library needed.
object RainCloud {
    private val client = OkHttpClient()

    // 👇 Your database address — pasted once, dropped in here for you
    private const val DB = "{{FIREBASE_URL}}"

    // Save one rain report (call this when the user taps the button)
    fun sendReport(lat: Double, lng: Double) {
        val json = """{"lat":$lat,"lng":$lng,"time":${System.currentTimeMillis()}}"""
        val body = json.toRequestBody("application/json".toMediaType())
        val request = Request.Builder().url("$DB/reports.json").post(body).build()
        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) { /* offline — try later */ }
            override fun onResponse(call: Call, response: Response) { response.close() }
        })
    }

    // Download all recent reports (as text) so we can show them
    fun loadReports(onResult: (String) -> Unit) {
        val request = Request.Builder().url("$DB/reports.json").get().build()
        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) { onResult("{}") }
            override fun onResponse(call: Call, response: Response) {
                onResult(response.body?.string() ?: "{}"); response.close()
            }
        })
    }
}

class MapManager(
    private val googleMap: GoogleMap,
    private val database: DatabaseReference
) {
    // Track active markers by report ID to enable updates/removal
    private val activeMarkers = mutableMapOf<String, Marker>()

    fun startListening() {
        database.child("rain_reports")
            .addChildEventListener(object : ChildEventListener {
                override fun onChildAdded(
                    snapshot: DataSnapshot, previousKey: String?
                ) {
                    snapshot.children.forEach { reportSnap ->
                        val r = reportSnap.getValue(RainReport::class.java)
                        if (r != null && !isExpired(r)) addMarker(r)
                    }
                }
                override fun onChildChanged(
                    snapshot: DataSnapshot, previousKey: String?
                ) {
                    snapshot.children.forEach { reportSnap ->
                        val r = reportSnap.getValue(RainReport::class.java)
                        if (r != null) {
                            if (isExpired(r)) removeMarker(r.id)
                            else addMarker(r)
                        }
                    }
                }
                override fun onChildRemoved(s: DataSnapshot) {}
                override fun onChildMoved(s: DataSnapshot, p: String?) {}
                override fun onCancelled(e: DatabaseError) {}
            })
    }

    private fun addMarker(report: RainReport) {
        val latLng = districtToLatLng(report.district) ?: return
        val hue = when (report.intensity) {
            "LIGHT"  -> BitmapDescriptorFactory.HUE_AZURE
            "HEAVY"  -> BitmapDescriptorFactory.HUE_RED
            else     -> BitmapDescriptorFactory.HUE_BLUE
        }
        val options = MarkerOptions()
            .position(latLng)
            .title(report.district)
            .snippet("${report.intensity} • ${timeAgo(report.timestamp)}")
            .icon(BitmapDescriptorFactory.defaultMarker(hue))

        activeMarkers[report.id]?.remove()        // remove old if exists
        activeMarkers[report.id] = googleMap.addMarker(options)!!
    }

    private fun isExpired(r: RainReport): Boolean {
        val twoHours = 2 * 60 * 60 * 1000L
        return System.currentTimeMillis() - r.timestamp > twoHours
    }

    private fun timeAgo(ts: Long): String {
        val diff = (System.currentTimeMillis() - ts) / 60000
        return when {
            diff < 1  -> "Vừa xong"
            diff < 60 -> "$diff phút trước"
            else      -> "${diff / 60} giờ trước"
        }
    }

    private fun removeMarker(id: String) {
        activeMarkers.remove(id)?.remove()
    }
}

class MainViewModel(application: Application) : AndroidViewModel(application) {

    private val locationMgr = LocationManager(application)
    private val reportMgr = ReportManager()

    // StateFlows — UI observes these and redraws when they change
    private val _district = MutableStateFlow("Đang xác định vị trí...")
    val district = _district.asStateFlow()

    private val _reports = MutableStateFlow<List<RainReport>>(emptyList())
    val reports = _reports.asStateFlow()

    private val _isSubmitting = MutableStateFlow(false)
    val isSubmitting = _isSubmitting.asStateFlow()

    init {
        detectLocation()  // runs once when ViewModel is first created
    }

    private fun detectLocation() {
        locationMgr.getCurrentDistrict(
            onResult = { district ->
                _district.value = district
                subscribeToDistrict(district)
                // Subscribe to FCM topic for this district
                val topicKey = district.lowercase().replace(" ", "-")
                FirebaseMessaging.getInstance()
                    .subscribeToTopic("rain-alerts-$topicKey")
            },
            onPermissionDenied = {
                _district.value = "Chọn quận thủ công"
            }
        )
    }

    private fun subscribeToDistrict(district: String) {
        reportMgr.listenToDistrict(district) { newReports ->
            _reports.value = newReports
        }
    }

    fun submitRainReport(intensity: RainIntensity) {
        val currentDistrict = _district.value
        if (currentDistrict.startsWith("Đang")) return

        _isSubmitting.value = true
        val report = RainReport(
            district = currentDistrict,
            timestamp = System.currentTimeMillis(),
            intensity = intensity.name
        )
        reportMgr.submitReport(report) {
            _isSubmitting.value = false
        }
    }
}

// Free 'nearby alert' — the app checks for itself, no paid push server.
object NearbyRainChecker {
    private var lastSeenTime = 0L   // newest report we've already shown

    fun check(myLat: Double, myLng: Double, context: Context) {
        RainCloud.loadReports { jsonText ->
            val reports = JSONObject(jsonText)
            for (key in reports.keys()) {
                val r = reports.getJSONObject(key)
                val time = r.getLong("time")
                if (time <= lastSeenTime) continue          // already told about it

                val result = FloatArray(1)
                Location.distanceBetween(myLat, myLng, r.getDouble("lat"), r.getDouble("lng"), result)
                if (result[0] <= 5000) {                     // within 5 km
                    showNotification(context, "Rain reported nearby ☔",
                                     "Someone close to you just reported rain.")
                    lastSeenTime = time                      // don't repeat it
                }
            }
        }
    }
}

