// BEFORE — crashes on Android 12+ (API 31+)
val pendingIntent = PendingIntent.getActivity(
    this,
    0,
    tapIntent,
    PendingIntent.FLAG_UPDATE_CURRENT  // missing required flag!
)

// AFTER — works on all Android versions
val pendingIntent = PendingIntent.getActivity(
    this,
    0,
    tapIntent,
    PendingIntent.FLAG_UPDATE_CURRENT or
    PendingIntent.FLAG_IMMUTABLE      // required from Android 12+
)

// WHY FLAG_IMMUTABLE?
// Security: prevents other apps from intercepting and modifying
// the intent payload (e.g., changing the 'district' extra)
//
// FLAG_UPDATE_CURRENT: if this PendingIntent already exists,
// update its extras with the new values (important for
// different rain alert districts)
//
// Bitwise OR combines flags:
// FLAG_UPDATE_CURRENT = 134217728 (binary: 1000...)
// FLAG_IMMUTABLE      = 67108864  (binary: 0100...)
// Combined            = 201326592 (binary: 1100...)
